All tests pass. Here is the fixed module:

```python
from collections import OrderedDict


class TTLCache:
    def __init__(self, capacity):
        if capacity <= 0:
            raise ValueError("capacity must be positive")
        self.capacity = capacity
        self._d = OrderedDict()   # key -> (value, expires_at)
        self._hits = 0
        self._misses = 0

    def put(self, key, value, now, ttl):
        if key in self._d:
            self._d[key] = (value, now + ttl)
            self._d.move_to_end(key, last=True)
            return
        if len(self._d) >= self.capacity:
            for k in list(self._d):
                _, exp = self._d[k]
                if exp <= now:
                    del self._d[k]
            if len(self._d) >= self.capacity:
                self._d.popitem(last=False)
        self._d[key] = (value, now + ttl)

    def get(self, key, now):
        if key not in self._d:
            self._misses += 1
            return None
        value, expires_at = self._d[key]
        if now >= expires_at:
            del self._d[key]
            self._misses += 1
            return None
        self._hits += 1
        self._d.move_to_end(key, last=True)
        return value

    def stats(self):
        return (self._hits, self._misses)

    def __len__(self):
        return len(self._d)
```

Bugs fixed: overwrite now marks the key most-recently-used (`last=True`); expired-purge in `put` deletes entries where `exp <= now` (was deleting live ones); LRU eviction pops the front (`last=False`, was popping the most-recent); expiry check is inclusive (`now >= expires_at`); and an expired `get` now deletes the entry, counts a miss (was counting a hit and leaving it in place).
